// ----- МОБИЛЬНАЯ ВЕРСИЯ ДЕФОЛТНОГО БАННЕРА (328x364) -----
const MobileCustomizableBanner = ({
  tokens,
  currencyName,
}: {
  tokens: ColorTokens;
  currencyName?: string;
}) => {
  const bg = tokens.background;
  const txt = tokens.text;
  const icons = tokens.icons;
  const displayCurrency = (currencyName?.trim() || "Teal");

  return (
    <div
      className="flex w-[328px] h-[364px] flex-col overflow-hidden rounded-lg border"
      style={{
        backgroundColor: getColor(bg.island),
        borderColor: getColor(bg.border),
      }}
    >
      <div className="flex flex-1 flex-col justify-center p-3">
        <h1
          className="text-xl font-extrabold leading-6"
          style={{ color: getColor(txt.primary) }}
        >
          Программа лояльности
        </h1>
        <p
          className="mt-1 text-sm font-bold leading-5"
          style={{ color: getColor(txt.primary) }}
        >
          «С вас – активность, с нас – {displayCurrency}!»
        </p>
        <p
          className="mt-1 text-xs leading-4"
          style={{ color: getColor(txt.primary) }}
        >
          Получай внутреннюю валюту {displayCurrency} за участие в корпоративных активностях
          и получай брендированный мерч компании и другие вознаграждения в
          онлайн-магазине.
        </p>
      </div>
      <div className="relative h-48 w-full flex-shrink-0 overflow-hidden">
        <div className="h-full w-full">
          <CoinsIcon accentColor={getColor(bg.accent)} />
        </div>
        <div className="absolute left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2">
          <CurrencyIcon
            color={getColor(icons["primary-inverse"])}
            width={3.5}
          />
        </div>
      </div>
    </div>
  );
};

// ----- ОСНОВНОЙ КОМПОНЕНТ МОБИЛЬНОГО БАННЕРА -----
export default function MobileBannerSection({
  tokens,
  fileData,
  currencyName,
  onUpload,
  onRemove,
}: MobileBannerSectionProps) {
  const assetKey = "bannerMobile";

  return (
    <div className="rounded-xl border border-border bg-background p-4 shadow-sm">
      <div className="mb-3 flex items-center justify-between">
        <div>
          <p className="text-sm font-medium">Мобильный баннер</p>
          <p className="text-xs text-muted-foreground">
            Минимальные размеры 328×364px, макс. 3 МБ
          </p>
        </div>
        {!fileData ? (
          <label
            htmlFor={`upload-${assetKey}`}
            className="flex cursor-pointer items-center gap-1 rounded-md bg-primary/10 px-2 py-1 text-xs font-medium text-primary hover:bg-primary/20"
          >
            <Upload size={14} />
            Загрузить
          </label>
        ) : (
          <button
            onClick={() => onRemove(assetKey)}
            className="rounded-md p-1 text-muted-foreground hover:bg-muted"
            title="Удалить"
          >
            <X size={16} />
          </button>
        )}
        {/* Добавлен key для сброса input при удалении */}
        <input
          key={fileData ? "uploaded" : "empty"}
          id={`upload-${assetKey}`}
          type="file"
          accept="image/png,image/jpeg,image/svg+xml"
          className="hidden"
          onChange={(e) => {
            const file = e.target.files?.[0];
            if (file) onUpload(assetKey, file);
          }}
        />
      </div>

      <div className="flex justify-center">
        {fileData ? (
          <div
            className="flex items-center justify-center overflow-hidden rounded-lg border border-border/50 bg-muted/30"
            style={{ width: 328, height: 364 }}
          >
            <img
              src={fileData}
              alt="Мобильный баннер"
              className="h-full w-full object-cover rounded-lg"
            />
          </div>
        ) : (
          <MobileCustomizableBanner tokens={tokens} currencyName={currencyName} />
        )}
      </div>
    </div>
  );
}
